def is_prime(n):
    if n <= 1:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

# Testing the function with 17 and 24
test_numbers = [17, 24]
results = {n: is_prime(n) for n in test_numbers}
results

